-- ================================================================
-- AUDELY DESKTOP — Setup complet (schéma + données)
-- ================================================================
-- Usage :
--   1. Créer la base :  CREATE DATABASE audely_desktop CHARACTER SET utf8mb4;
--   2. Lancer ce fichier : mysql -u <user> -p audely_desktop < BDD/setup_complet.sql
-- ================================================================

SET FOREIGN_KEY_CHECKS = 0;

-- ── Schéma ──────────────────────────────────────────────────────

DROP TABLE IF EXISTS Resultats;
DROP TABLE IF EXISTS Exercices;
DROP TABLE IF EXISTS Categorie;
DROP TABLE IF EXISTS Utilisateur;

CREATE TABLE Utilisateur (
  id            INT AUTO_INCREMENT,
  nom           VARCHAR(100) NOT NULL,
  prenom        VARCHAR(100) NOT NULL,
  mail          VARCHAR(255) NOT NULL UNIQUE,
  mot_de_passe  VARCHAR(255) NOT NULL,
  created_at    TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE Categorie (
  id    INT AUTO_INCREMENT,
  titre VARCHAR(100) NOT NULL,
  PRIMARY KEY (id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE Exercices (
  id             INT AUTO_INCREMENT,
  titre          VARCHAR(150) NOT NULL,
  niveau         ENUM('facile','moyen','difficile') NOT NULL,
  description    TEXT NOT NULL,
  audio_url      VARCHAR(255) NOT NULL,
  categorie_id   INT DEFAULT NULL,
  type_exercice  VARCHAR(50) NOT NULL DEFAULT 'detecter',
  contenu        JSON DEFAULT NULL,
  PRIMARY KEY (id),
  CONSTRAINT FK_Exercices_Categorie FOREIGN KEY (categorie_id)
    REFERENCES Categorie(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE Resultats (
  id             INT AUTO_INCREMENT,
  id_utilisateur INT NOT NULL,
  id_exercice    INT NOT NULL,
  score          INT NOT NULL,
  date_session   DATETIME DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  CONSTRAINT FK_Resultats_Utilisateur FOREIGN KEY (id_utilisateur)
    REFERENCES Utilisateur(id) ON DELETE CASCADE,
  CONSTRAINT FK_Resultats_Exercices FOREIGN KEY (id_exercice)
    REFERENCES Exercices(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ── Catégories ──────────────────────────────────────────────────

INSERT INTO Categorie (id, titre) VALUES
(3, 'Détecter'),
(4, 'Reconnaître'),
(5, 'Distinguer'),
(6, 'Comprendre'),
(7, 'Mémoriser'),
(8, 'Thèmes');

-- ── Exercices ───────────────────────────────────────────────────

INSERT INTO `Exercices` (`id`, `titre`, `niveau`, `description`, `audio_url`, `categorie_id`, `type_exercice`, `contenu`) VALUES (1,'Grave ou aigu ?','facile','Identifie si le son est grave ou aigu','/audio/ex1.mp3',3,'grave_aigu','{\"mots\": [\"chat\", \"maison\", \"soleil\", \"porte\", \"jardin\", \"fleur\", \"voiture\", \"nuit\", \"table\", \"musique\"], \"instructions\": \"Votre partenaire prononce un mot avec une voix grave ou aiguë. Dites si c\'est grave ou aigu.\", \"consigne_partenaire\": \"Prononcez chaque mot soit avec une voix grave, soit avec une voix aiguë, dans un ordre aléatoire.\"}'),(2,'Repérer le son','facile','Écoutez l\'enregistrement et cliquez chaque fois que vous entendez un son.','/audio/reperer-son.mp3',3,'detecter','{\"mots\": [\"soleil\", \"maison\", \"chat\", \"sac\", \"porte\", \"saison\", \"table\", \"son\", \"forêt\", \"semaine\", \"lumière\", \"soir\"], \"son_cible\": \"S\", \"instructions\": \"Écoutez l\'enregistrement et levez la main chaque fois que vous entendez le son cible.\", \"consigne_partenaire\": \"Prononcez la liste de mots. L\'auditeur doit réagir chaque fois qu\'il entend le son cible.\"}'),(3,'Son grave ou aigu','facile','Écoutez et déterminez si le son est grave ou aigu.','/audio/grave-aigu.mp3',3,'grave_aigu','{\"syllabes\": [\"ah\", \"oh\", \"ii\", \"ou\", \"eu\", \"an\", \"on\", \"in\"], \"instructions\": \"Écoutez et déterminez si le son est grave ou aigu.\", \"consigne_partenaire\": \"Prononcez chaque syllabe soit avec une voix grave soit avec une voix aiguë.\"}'),(4,'Mot court ou long ?','moyen','Écoutez et déterminez si la durée du son est courte ou longue.','/audio/duree-son.mp3',3,'detecter','{\"mots\": [{\"mot\": \"pain\", \"type\": \"court\"}, {\"mot\": \"téléphone\", \"type\": \"long\"}, {\"mot\": \"chat\", \"type\": \"court\"}, {\"mot\": \"calendrier\", \"type\": \"long\"}, {\"mot\": \"mer\", \"type\": \"court\"}, {\"mot\": \"chocolat\", \"type\": \"long\"}, {\"mot\": \"nuit\", \"type\": \"court\"}, {\"mot\": \"ordinateur\", \"type\": \"long\"}, {\"mot\": \"eau\", \"type\": \"court\"}, {\"mot\": \"télévision\", \"type\": \"long\"}], \"instructions\": \"Écoutez le mot et dites s\'il est court (1 syllabe) ou long (3 syllabes).\"}'),(5,'1 ou 2 sons ?','moyen','Combien de sons distincts entendez-vous dans cet extrait ?','/audio/un-ou-deux.mp3',3,'detecter','{\"series\": [{\"sons\": 1}, {\"sons\": 2}, {\"sons\": 1}, {\"sons\": 2}, {\"sons\": 2}, {\"sons\": 1}, {\"sons\": 2}, {\"sons\": 1}, {\"sons\": 1}, {\"sons\": 2}], \"instructions\": \"Votre partenaire produit un ou deux sons. Dites combien vous en entendez.\", \"consigne_partenaire\": \"Frappez dans vos mains une ou deux fois avec une courte pause entre les deux si besoin.\"}'),(6,'Reconnaître un animal','moyen','Quel animal entendez-vous dans cet enregistrement ?','/audio/animal.mp3',4,'reconnaitre','{\"animaux\": [{\"animal\": \"Le chien\", \"indices\": [\"C\'est un animal domestique\", \"Il aboie\", \"Il est souvent appelé meilleur ami de l\'homme\"]}, {\"animal\": \"Le chat\", \"indices\": [\"Il ronronne\", \"Il aime dormir au soleil\", \"Il est très indépendant\"]}, {\"animal\": \"Le coq\", \"indices\": [\"Il chante le matin\", \"Il vit à la ferme\", \"Il a un plumage coloré\"]}, {\"animal\": \"La grenouille\", \"indices\": [\"Elle coasse\", \"Elle vit près de l\'eau\", \"Elle saute très haut\"]}, {\"animal\": \"L\'éléphant\", \"indices\": [\"C\'est le plus grand animal terrestre\", \"Il a une trompe\", \"Il vit en Afrique ou en Asie\"]}, {\"animal\": \"Le hibou\", \"indices\": [\"Il sort la nuit\", \"Il fait \'hou hou\'\", \"Il tourne la tête à 270 degrés\"]}], \"instructions\": \"Votre partenaire décrit un animal. Devinez lequel.\", \"consigne_partenaire\": \"Décrivez l\'animal sans le nommer : où il vit, ce qu\'il mange, ses caractéristiques.\"}'),(7,'Reconnaître un instrument','moyen','Quel instrument de musique est joué dans cet extrait ?','/audio/instrument.mp3',4,'reconnaitre','{\"instruments\": [{\"indices\": [\"On appuie sur des touches noires et blanches\", \"Il peut être très grand\", \"Beethoven en jouait\"], \"instrument\": \"Le piano\"}, {\"indices\": [\"On pince des cordes\", \"On peut en jouer assis\", \"Très utilisée en rock\"], \"instrument\": \"La guitare\"}, {\"indices\": [\"On le tient sous le menton\", \"On utilise un archet\", \"C\'est un instrument à cordes frottées\"], \"instrument\": \"Le violon\"}, {\"indices\": [\"On souffle dedans\", \"C\'est un tube long et fin\", \"Elle produit des sons aigus\"], \"instrument\": \"La flûte\"}, {\"indices\": [\"On le frappe avec des baguettes\", \"Il donne le rythme\", \"Il est composé de plusieurs tambours\"], \"instrument\": \"La batterie\"}], \"instructions\": \"Votre partenaire décrit un instrument de musique. Nommez-le.\", \"consigne_partenaire\": \"Décrivez l\'instrument sans le nommer : apparence, comment on en joue, quel son il produit.\"}'),(8,'Reconnaître une voyelle','moyen','Quelle voyelle a été prononcée ?','/audio/voyelle.mp3',4,'reconnaitre','{\"voyelles\": [\"A\", \"E\", \"I\", \"O\", \"U\", \"OU\", \"AN\", \"ON\", \"IN\", \"EU\"], \"instructions\": \"Votre partenaire prononce une voyelle isolée. Identifiez laquelle.\", \"consigne_partenaire\": \"Prononcez chaque voyelle clairement et de façon isolée.\"}'),(9,'Reconnaître une émotion','difficile','Quelle émotion exprime cette voix ?','/audio/emotion.mp3',4,'reconnaitre','{\"emotions\": [\"joie\", \"tristesse\", \"colère\", \"surprise\", \"peur\", \"ennui\", \"enthousiasme\"], \"instructions\": \"Votre partenaire lit la même phrase avec différentes émotions. Identifiez l\'émotion.\", \"phrase_support\": \"Je vais aller faire les courses cet après-midi.\", \"consigne_partenaire\": \"Lisez toujours la même phrase mais avec l\'émotion indiquée. Ne dites pas l\'émotion.\"}'),(10,'Suivez le rythme','moyen','Entraînez-vous à reconnaître le rythme.','',4,'reconnaitre_rythme','{\"rythmes\": [{\"notation\": \"court-court-long\", \"description\": \"2 frappes rapides puis 1 longue\"}, {\"notation\": \"long-court-court-court\", \"description\": \"1 longue puis 3 rapides\"}, {\"notation\": \"court-long-court\", \"description\": \"1 courte, 1 longue, 1 courte\"}, {\"notation\": \"long-long-court\", \"description\": \"2 longues puis 1 courte\"}, {\"notation\": \"court-court-court-long\", \"description\": \"3 rapides puis 1 longue\"}], \"instructions\": \"Écoutez le rythme frappé par votre partenaire et reproduisez-le.\", \"consigne_partenaire\": \"Frappez chaque rythme sur la table. L\'auditeur doit le reproduire.\"}'),(11,'Identique ou différent','facile','Vous allez entendre deux sons : dites s\'ils sont pareils ou différents.','',5,'distinguer','{\"paires\": [{\"mot1\": \"pain\", \"mot2\": \"bain\", \"resultat\": \"différent\"}, {\"mot1\": \"sou\", \"mot2\": \"sou\", \"resultat\": \"pareil\"}, {\"mot1\": \"mer\", \"mot2\": \"mer\", \"resultat\": \"pareil\"}, {\"mot1\": \"vert\", \"mot2\": \"fer\", \"resultat\": \"différent\"}, {\"mot1\": \"vin\", \"mot2\": \"lin\", \"resultat\": \"différent\"}, {\"mot1\": \"rue\", \"mot2\": \"rue\", \"resultat\": \"pareil\"}], \"instructions\": \"Votre partenaire prononce deux mots. Dites s\'ils sont pareils ou différents.\", \"consigne_partenaire\": \"Prononcez les deux mots l\'un après l\'autre. Certaines paires sont identiques.\"}'),(12,'Identique ou différent','facile','Vous allez entendre deux sons : dites s\'ils sont pareils ou différents.','',5,'distinguer','{\"paires\": [{\"mot1\": \"pont\", \"mot2\": \"bond\", \"resultat\": \"différent\"}, {\"mot1\": \"tôt\", \"mot2\": \"tôt\", \"resultat\": \"pareil\"}, {\"mot1\": \"cou\", \"mot2\": \"genou\", \"resultat\": \"différent\"}, {\"mot1\": \"chat\", \"mot2\": \"gat\", \"resultat\": \"différent\"}, {\"mot1\": \"fin\", \"mot2\": \"fin\", \"resultat\": \"pareil\"}, {\"mot1\": \"belle\", \"mot2\": \"pelle\", \"resultat\": \"différent\"}], \"instructions\": \"Votre partenaire prononce deux mots. Dites s\'ils sont pareils ou différents.\", \"consigne_partenaire\": \"Prononcez les deux mots l\'un après l\'autre. Niveau plus difficile.\"}'),(13,'Son fort ou faible ?','facile','Écoutez et déterminez si le son est fort ou faible.','/audio/fort-faible.mp3',3,'detecter','{\"phrases\": [\"Bonjour, comment allez-vous ?\", \"Il fait beau aujourd\'hui.\", \"J\'ai faim, allons manger.\", \"La porte est ouverte.\", \"C\'est l\'heure du dîner.\", \"Le train part dans cinq minutes.\"], \"instructions\": \"Votre partenaire prononce une phrase soit fort soit doucement. Identifiez l\'intensité.\", \"consigne_partenaire\": \"Lisez chaque phrase en alternant fort et doucement dans un ordre aléatoire.\"}'),(14,'Compter les syllabes','moyen','Combien de fois le son est-il répété ? Comptez attentivement.','/audio/compter-frappes.mp3',3,'detecter','{\"syllabes\": [{\"nb\": 1, \"mot\": \"mer\"}, {\"nb\": 1, \"mot\": \"chat\"}, {\"nb\": 1, \"mot\": \"nuit\"}, {\"nb\": 2, \"mot\": \"maison\"}, {\"nb\": 2, \"mot\": \"soleil\"}, {\"nb\": 2, \"mot\": \"bateau\"}, {\"nb\": 2, \"mot\": \"cahier\"}, {\"nb\": 3, \"mot\": \"chocolat\"}, {\"nb\": 3, \"mot\": \"téléphone\"}, {\"nb\": 3, \"mot\": \"araignée\"}], \"instructions\": \"Écoutez le mot et comptez ses syllabes.\"}'),(15,'Reconnaître un bruit du quotidien','moyen','Quel bruit de la vie quotidienne entendez-vous ?','/audio/bruit-quotidien.mp3',4,'reconnaitre','{\"sons\": [{\"son\": \"La pluie\", \"description\": \"C\'est un bruit continu de gouttes qui tombent sur les vitres\"}, {\"son\": \"La sonnerie du téléphone\", \"description\": \"C\'est un son répétitif qui vous appelle à répondre\"}, {\"son\": \"Le micro-ondes\", \"description\": \"C\'est un bip court qui annonce que votre plat est chaud\"}, {\"son\": \"Un chien qui aboie\", \"description\": \"C\'est le cri d\'un animal domestique qui surveille la maison\"}, {\"son\": \"La cafetière\", \"description\": \"C\'est un gargouillis régulier qui prépare votre boisson du matin\"}, {\"son\": \"Une clé dans la serrure\", \"description\": \"C\'est un bruit métallique suivi d\'un clic quand on entre chez soi\"}], \"instructions\": \"Votre partenaire décrit un son sans le nommer. Devinez de quel son il s\'agit.\", \"consigne_partenaire\": \"Décrivez le son avec des mots, sans le nommer directement.\"}'),(16,'Reconnaître une consonne','moyen','Quelle consonne a été prononcée dans cet extrait ?','/audio/consonne.mp3',4,'reconnaitre','{\"consonnes\": [\"P\", \"B\", \"T\", \"D\", \"K\", \"G\", \"F\", \"V\", \"S\", \"Z\", \"CH\", \"J\", \"M\", \"N\", \"L\", \"R\"], \"instructions\": \"Votre partenaire prononce une consonne isolée. Identifiez laquelle.\", \"consigne_partenaire\": \"Prononcez chaque consonne clairement, dans un ordre aléatoire.\"}'),(17,'Même son ou différent ?','facile','Écoutez deux sons. Sont-ils identiques ou différents ?','/audio/meme-different.mp3',5,'distinguer','{\"paires\": [{\"mot1\": \"pain\", \"mot2\": \"bain\", \"resultat\": \"différent\"}, {\"mot1\": \"sou\", \"mot2\": \"sou\", \"resultat\": \"pareil\"}, {\"mot1\": \"vert\", \"mot2\": \"fer\", \"resultat\": \"différent\"}, {\"mot1\": \"tôt\", \"mot2\": \"tôt\", \"resultat\": \"pareil\"}, {\"mot1\": \"vin\", \"mot2\": \"lin\", \"resultat\": \"différent\"}, {\"mot1\": \"pont\", \"mot2\": \"bond\", \"resultat\": \"différent\"}, {\"mot1\": \"rue\", \"mot2\": \"rue\", \"resultat\": \"pareil\"}, {\"mot1\": \"cou\", \"mot2\": \"genou\", \"resultat\": \"différent\"}, {\"mot1\": \"mer\", \"mot2\": \"mer\", \"resultat\": \"pareil\"}, {\"mot1\": \"chat\", \"mot2\": \"gat\", \"resultat\": \"différent\"}], \"instructions\": \"Votre partenaire prononce deux mots. Dites s\'ils sont pareils ou différents.\", \"consigne_partenaire\": \"Prononcez les deux mots l\'un après l\'autre avec une courte pause.\"}'),(18,'Grave ou aigu ? Comparaison','facile','Deux sons sont joués. Lequel est le plus grave ?','/audio/grave-aigu-comp.mp3',5,'distinguer','{\"paires\": [{\"mot_aigu\": \"oiseau\", \"mot_grave\": \"voiture\"}, {\"mot_aigu\": \"flûte\", \"mot_grave\": \"montagne\"}, {\"mot_aigu\": \"cloche\", \"mot_grave\": \"tambour\"}, {\"mot_aigu\": \"cigale\", \"mot_grave\": \"forêt\"}, {\"mot_aigu\": \"sifflet\", \"mot_grave\": \"tonnerre\"}], \"instructions\": \"Votre partenaire prononce deux mots, l\'un grave l\'un aigu. Identifiez lequel est grave.\", \"consigne_partenaire\": \"Prononcez les deux mots dans un ordre aléatoire, l\'un grave, l\'autre aigu.\"}'),(19,'Deux mots proches','moyen','Écoutez deux mots similaires. Lesquels entendez-vous ?','/audio/deux-mots.mp3',5,'distinguer','{\"paires\": [[\"mer\", \"mère\"], [\"pain\", \"bain\"], [\"vert\", \"fer\"], [\"son\", \"bon\"], [\"tante\", \"dente\"], [\"pile\", \"bile\"], [\"four\", \"tour\"], [\"sac\", \"bac\"], [\"lent\", \"rang\"], [\"peur\", \"beurre\"]], \"instructions\": \"Votre partenaire choisit et prononce un mot parmi deux mots phonétiquement proches. Identifiez lequel.\", \"consigne_partenaire\": \"Choisissez un mot au hasard dans chaque paire et prononcez-le naturellement.\"}'),(20,'Distinguer des syllabes','moyen','Entendez-vous « pa » ou « ba » ? Distinguez les syllabes proches.','/audio/syllabes.mp3',5,'distinguer','{\"paires\": [[\"pa\", \"ba\"], [\"ta\", \"da\"], [\"ka\", \"ga\"], [\"fa\", \"va\"], [\"sa\", \"za\"], [\"si\", \"zi\"], [\"po\", \"bo\"], [\"tu\", \"du\"], [\"fi\", \"vi\"], [\"chou\", \"joue\"]], \"instructions\": \"Votre partenaire prononce une syllabe. Dites laquelle vous avez entendue.\", \"consigne_partenaire\": \"Prononcez la syllabe choisie clairement, sans exagérer.\"}'),(21,'Sons similaires','difficile','Identifiez laquelle de ces quatre syllabes a été prononcée.','/audio/sons-similaires.mp3',5,'distinguer','{\"groupes\": [[\"mer\", \"mère\", \"maire\", \"mais\"], [\"son\", \"sans\", \"sang\", \"cent\"], [\"vert\", \"ver\", \"verre\", \"vers\"], [\"pain\", \"pin\", \"bain\", \"bien\"], [\"saint\", \"sain\", \"sein\", \"cinq\"], [\"cou\", \"coût\", \"coup\", \"queue\"]], \"instructions\": \"Votre partenaire choisit et prononce un mot parmi quatre mots très proches. Identifiez lequel.\", \"consigne_partenaire\": \"Pour chaque groupe, choisissez un mot au hasard et prononcez-le naturellement.\"}'),(22,'Complétez la phrase','difficile','Votre partenaire lit une phrase avec un mot manquant. Identifiez le mot prononcé.','',6,'comprendre','{\"phrases\": [{\"phrase\": \"Ce matin, j\'ai bu mon ...... chaud.\", \"alternatives\": [\"café\", \"thé\", \"lait\", \"chocolat\"]}, {\"phrase\": \"Il fait froid, prends ton ......\", \"alternatives\": [\"manteau\", \"chapeau\", \"parapluie\"]}, {\"phrase\": \"J\'ai lu un bon ...... ce week-end.\", \"alternatives\": [\"livre\", \"journal\", \"magazine\"]}, {\"phrase\": \"On mange à quelle ...... ce soir ?\", \"alternatives\": [\"heure\", \"table\", \"place\"]}, {\"phrase\": \"J\'ai acheté du ...... à la boulangerie.\", \"alternatives\": [\"pain\", \"croissant\", \"gâteau\"]}, {\"phrase\": \"Le médecin m\'a donné une ......\", \"alternatives\": [\"ordonnance\", \"pilule\", \"piqûre\"]}, {\"phrase\": \"Peux-tu ouvrir la ...... s\'il te plaît ?\", \"alternatives\": [\"fenêtre\", \"porte\", \"boîte\"]}, {\"phrase\": \"On a regardé un bon ...... hier soir.\", \"alternatives\": [\"film\", \"match\", \"spectacle\"]}, {\"phrase\": \"Le train part de quel ...... ?\", \"alternatives\": [\"quai\", \"billet\", \"wagon\"]}, {\"phrase\": \"Elle travaille à l\'...... depuis dix ans.\", \"alternatives\": [\"hôpital\", \"école\", \"université\"]}, {\"phrase\": \"J\'ai oublié mon ...... à la maison.\", \"alternatives\": [\"téléphone\", \"portefeuille\", \"trousseau\"]}, {\"phrase\": \"Le ...... est rouge ce soir, il fera beau demain.\", \"alternatives\": [\"ciel\", \"soleil\", \"nuage\"]}], \"instructions\": \"Votre partenaire vous montre les alternatives, puis lit la phrase en choisissant l\'un des mots. Dites lequel a été prononcé.\", \"consigne_partenaire\": \"Montrez la liste à l\'auditeur. Lisez la phrase en choisissant un mot au hasard sans le montrer.\"}'),(23,'Le bon contexte','difficile','Utilisez le contexte de la phrase pour trouver le mot manquant.','',6,'comprendre','{\"phrases\": [{\"phrase\": \"J\'avais très froid, alors j\'ai allumé le ......\", \"alternatives\": [\"chauffage\", \"ventilateur\", \"climatiseur\"]}, {\"phrase\": \"Elle était fatiguée, elle s\'est couchée sans regarder la ......\", \"alternatives\": [\"télévision\", \"fenêtre\", \"montre\"]}, {\"phrase\": \"Il avait oublié son parapluie et il est rentré complètement ......\", \"alternatives\": [\"trempé\", \"bronzé\", \"fatigué\"]}, {\"phrase\": \"Le gâteau était brûlé car elle l\'avait laissé trop longtemps dans le ......\", \"alternatives\": [\"four\", \"congélateur\", \"frigo\"]}, {\"phrase\": \"Il avait perdu ses clés et n\'a pas pu entrer dans sa ......\", \"alternatives\": [\"maison\", \"voiture\", \"valise\"]}, {\"phrase\": \"Il pleuvait fort, alors elle a pris son ...... avant de sortir.\", \"alternatives\": [\"parapluie\", \"manteau\", \"chapeau\"]}], \"instructions\": \"Votre partenaire lit une phrase entière. Utilisez le contexte pour identifier le mot prononcé.\", \"consigne_partenaire\": \"Lisez la phrase entière. L\'auditeur utilise le sens pour identifier le mot parmi les alternatives.\"}'),(24,'Phrases sur un sujet','difficile','Écoutez des phrases sur un même sujet et répétez-les.','',6,'comprendre','{\"themes\": [{\"theme\": \"La cuisine\", \"phrases\": [\"Qu\'est-ce qu\'on mange ce soir ?\", \"Le repas est prêt, tu peux venir.\", \"J\'ai fait une tarte aux pommes.\", \"Tu veux encore de la soupe ?\", \"Je mets la table pour quatre personnes.\"]}, {\"theme\": \"La santé\", \"phrases\": [\"Je n\'ai pas bien dormi cette nuit.\", \"J\'ai un rendez-vous chez le médecin.\", \"Il faut prendre ce médicament deux fois par jour.\", \"Comment vous sentez-vous aujourd\'hui ?\", \"Il faut boire suffisamment d\'eau.\"]}, {\"theme\": \"Les transports\", \"phrases\": [\"Le bus a du retard ce matin.\", \"À quelle heure part le prochain train ?\", \"Il faut composter son billet avant de monter.\", \"Il y a des embouteillages sur l\'autoroute.\", \"L\'avion atterrit dans vingt minutes.\"]}, {\"theme\": \"Les courses\", \"phrases\": [\"J\'ai besoin de pain et de lait.\", \"Le supermarché ferme à vingt heures.\", \"Tu as la liste de courses ?\", \"Les tomates sont en promotion aujourd\'hui.\", \"Il ne reste plus de farine, j\'en achète ?\"]}], \"instructions\": \"Votre partenaire annonce le thème, puis lit chaque phrase. Répétez-la.\", \"consigne_partenaire\": \"Annoncez le thème. Lisez chaque phrase lentement. Attendez que l\'auditeur répète avant de continuer.\"}'),(25,'Questions et réponses','difficile','Répondez aux questions posées par votre partenaire.','',6,'comprendre','{\"themes\": [{\"theme\": \"La journée\", \"questions\": [\"À quelle heure vous levez-vous en général ?\", \"Qu\'est-ce que vous mangez au petit-déjeuner ?\", \"Comment venez-vous ici ce matin ?\", \"Avez-vous bien dormi cette nuit ?\", \"Qu\'avez-vous fait hier soir ?\"]}, {\"theme\": \"Les loisirs\", \"questions\": [\"Qu\'aimez-vous faire le week-end ?\", \"Regardez-vous souvent la télévision ?\", \"Avez-vous un sport préféré ?\", \"Lisez-vous beaucoup ?\", \"Aimez-vous la musique ?\"]}], \"instructions\": \"Votre partenaire vous pose des questions. Répondez le plus naturellement possible.\", \"consigne_partenaire\": \"Posez chaque question clairement. Si l\'auditeur ne comprend pas, reformulez.\"}'),(26,'Retenir 3 mots','difficile','Écoutez trois mots et répétez-les dans le bon ordre.','',7,'memoriser','{\"listes\": [[\"pain\", \"lait\", \"beurre\"], [\"chat\", \"chien\", \"lapin\"], [\"rouge\", \"bleu\", \"vert\"], [\"table\", \"chaise\", \"lit\"], [\"lundi\", \"mercredi\", \"vendredi\"], [\"pomme\", \"poire\", \"cerise\"], [\"médecin\", \"infirmière\", \"pharmacien\"], [\"maison\", \"jardin\", \"garage\"]], \"instructions\": \"Votre partenaire dit trois mots. Répétez-les dans le même ordre sans les écrire.\", \"consigne_partenaire\": \"Dites les trois mots avec une courte pause entre chaque. Attendez 5 secondes avant de demander la réponse.\"}'),(27,'Mémoriser une séquence','difficile','Retenez l\'ordre d\'une séquence de mots ou d\'actions.','',7,'memoriser','{\"sequences\": [{\"contexte\": \"Ingrédients d\'une recette\", \"elements\": [\"farine\", \"oeufs\", \"lait\", \"sucre\", \"beurre\"]}, {\"contexte\": \"Étapes du matin\", \"elements\": [\"réveil\", \"douche\", \"petit-déjeuner\", \"habillage\", \"départ\"]}, {\"contexte\": \"Directions\", \"elements\": [\"tout droit\", \"à gauche\", \"à droite\", \"tout droit\", \"à gauche\"]}, {\"contexte\": \"Jours de rendez-vous\", \"elements\": [\"lundi matin\", \"mercredi après-midi\", \"vendredi matin\"]}, {\"contexte\": \"Liste de courses\", \"elements\": [\"tomates\", \"fromage\", \"jambon\", \"yaourt\", \"jus d\'orange\"]}], \"instructions\": \"Votre partenaire lit une liste de 4 à 5 éléments. Répétez-les dans le même ordre.\", \"consigne_partenaire\": \"Lisez la liste une seule fois à vitesse normale. Attendez 10 secondes avant de demander la réponse.\"}'),(28,'Retenir les détails d\'une histoire','difficile','Écoutez une courte histoire et répondez aux questions.','',7,'memoriser','{\"histoires\": [{\"texte\": \"Marie se lève tôt le samedi matin. Elle prend son panier en osier et marche jusqu\'au marché du quartier. Elle achète des légumes frais : des carottes, des poireaux et des champignons. Elle s\'arrête aussi chez le fromager pour prendre un camembert. En rentrant, elle croise son voisin Paul qui promène son chien.\", \"titre\": \"Le marché du samedi\", \"questions\": [{\"reponse\": \"Le samedi\", \"question\": \"Quel jour Marie va-t-elle au marché ?\"}, {\"reponse\": \"Un panier en osier\", \"question\": \"Qu\'est-ce qu\'elle emporte pour faire ses courses ?\"}, {\"reponse\": \"Carottes, poireaux ou champignons\", \"question\": \"Citez deux légumes qu\'elle achète.\"}, {\"reponse\": \"Un camembert\", \"question\": \"Qu\'achète-t-elle chez le fromager ?\"}, {\"reponse\": \"Son voisin Paul\", \"question\": \"Qui croise-t-elle en rentrant ?\"}]}, {\"texte\": \"Thomas a rendez-vous chez le médecin à quatorze heures trente. Il attend vingt minutes dans la salle d\'attente. Le médecin l\'examine et lui dit qu\'il a une légère grippe. Il lui prescrit du repos, beaucoup de liquides et lui donne une ordonnance. Thomas doit revenir dans une semaine si les symptômes persistent.\", \"titre\": \"Le rendez-vous médical\", \"questions\": [{\"reponse\": \"Quatorze heures trente\", \"question\": \"À quelle heure est le rendez-vous de Thomas ?\"}, {\"reponse\": \"Vingt minutes\", \"question\": \"Combien de temps attend-il ?\"}, {\"reponse\": \"Une légère grippe\", \"question\": \"Quel est le diagnostic ?\"}, {\"reponse\": \"Du repos et beaucoup de liquides\", \"question\": \"Que lui conseille le médecin ?\"}, {\"reponse\": \"Dans une semaine\", \"question\": \"Quand doit-il revenir ?\"}]}], \"instructions\": \"Votre partenaire lit une courte histoire. Écoutez attentivement, puis répondez aux questions.\", \"consigne_partenaire\": \"Lisez l\'histoire une fois à voix haute. Posez ensuite les questions une par une.\"}'),(29,'Rappel différé','difficile','Mémorisez une liste, faites autre chose, puis rappelez-vous.','',7,'memoriser','{\"listes\": [{\"theme\": \"Choses à faire aujourd\'hui\", \"elements\": [\"appeler le médecin\", \"acheter du pain\", \"arroser les plantes\", \"rappeler Sophie\", \"prendre les médicaments\", \"sortir les poubelles\"]}, {\"theme\": \"Pays d\'Europe\", \"elements\": [\"France\", \"Allemagne\", \"Italie\", \"Espagne\", \"Portugal\", \"Belgique\", \"Suisse\"]}, {\"theme\": \"Animaux de la ferme\", \"elements\": [\"vache\", \"cochon\", \"mouton\", \"chèvre\", \"canard\", \"poule\", \"lapin\", \"cheval\"]}], \"instructions\": \"Votre partenaire vous lit une liste. Vous discutez d\'autre chose pendant 2 minutes, puis vous rappelez le maximum d\'éléments.\", \"consigne_partenaire\": \"Lisez la liste lentement. Pendant 2 minutes, parlez d\'autre chose. Demandez ensuite quels éléments ont été retenus.\"}'),(30,'Thème : La météo','difficile','Phrases du quotidien sur le thème de la météo.','',8,'themes','{\"theme\": \"La météo\", \"phrases\": [{\"texte\": \"Il fait beau aujourd\'hui.\", \"mot_cle\": \"beau\"}, {\"texte\": \"N\'oublie pas ton parapluie, il va pleuvoir.\", \"mot_cle\": \"parapluie\"}, {\"texte\": \"Le vent est très fort ce matin.\", \"mot_cle\": \"vent\"}, {\"texte\": \"On annonce de la neige pour ce week-end.\", \"mot_cle\": \"neige\"}, {\"texte\": \"Il fait trop chaud pour sortir en plein soleil.\", \"mot_cle\": \"chaud\"}, {\"texte\": \"Le ciel est couvert, on ne voit pas le soleil.\", \"mot_cle\": \"couvert\"}, {\"texte\": \"La température va descendre ce soir.\", \"mot_cle\": \"température\"}, {\"texte\": \"C\'est une belle journée ensoleillée.\", \"mot_cle\": \"ensoleillée\"}], \"instructions\": \"Votre partenaire annonce le thème puis lit chaque phrase. Répétez-la. En cas de difficulté, le mot clé est un indice.\", \"consigne_partenaire\": \"Annoncez le thème. Lisez chaque phrase normalement. En cas de difficulté, prononcez le mot clé seul.\"}'),(31,'Thème : La famille','difficile','Phrases du quotidien sur le thème de la famille.','',8,'themes','{\"theme\": \"La famille\", \"phrases\": [{\"texte\": \"Ma fille a eu son baccalauréat cette année.\", \"mot_cle\": \"fille\"}, {\"texte\": \"Mon frère habite à Lyon depuis cinq ans.\", \"mot_cle\": \"frère\"}, {\"texte\": \"Nous allons fêter l\'anniversaire de grand-mère dimanche.\", \"mot_cle\": \"anniversaire\"}, {\"texte\": \"Mes enfants rentrent de l\'école à seize heures.\", \"mot_cle\": \"enfants\"}, {\"texte\": \"Mon mari prépare le dîner ce soir.\", \"mot_cle\": \"mari\"}, {\"texte\": \"On se retrouve tous en famille à Noël.\", \"mot_cle\": \"famille\"}, {\"texte\": \"Ma sœur vient me rendre visite ce week-end.\", \"mot_cle\": \"soeur\"}, {\"texte\": \"Le bébé a fait ses premiers pas hier.\", \"mot_cle\": \"premiers pas\"}], \"instructions\": \"Votre partenaire annonce le thème puis lit chaque phrase. Répétez-la.\", \"consigne_partenaire\": \"Annoncez le thème. Lisez chaque phrase normalement.\"}'),(32,'Thème : Le travail','difficile','Phrases du quotidien sur le thème du travail.','',8,'themes','{\"theme\": \"Le travail\", \"phrases\": [{\"texte\": \"J\'ai une réunion importante à neuf heures.\", \"mot_cle\": \"réunion\"}, {\"texte\": \"Mon collègue est en congé maladie cette semaine.\", \"mot_cle\": \"congé\"}, {\"texte\": \"Il faut envoyer ce rapport avant vendredi.\", \"mot_cle\": \"rapport\"}, {\"texte\": \"Je travaille en télétravail le vendredi.\", \"mot_cle\": \"télétravail\"}, {\"texte\": \"On cherche quelqu\'un pour remplacer le directeur.\", \"mot_cle\": \"directeur\"}, {\"texte\": \"J\'ai eu une augmentation ce mois-ci.\", \"mot_cle\": \"augmentation\"}, {\"texte\": \"L\'entretien d\'embauche s\'est bien passé.\", \"mot_cle\": \"entretien\"}, {\"texte\": \"On a fini le projet en avance sur le planning.\", \"mot_cle\": \"projet\"}], \"instructions\": \"Votre partenaire annonce le thème puis lit chaque phrase. Répétez-la.\", \"consigne_partenaire\": \"Annoncez le thème. En cas de difficulté, dites le mot clé.\"}'),(33,'Thème : Les voyages','difficile','Phrases du quotidien sur le thème des voyages.','',8,'themes','{\"theme\": \"Les voyages\", \"phrases\": [{\"texte\": \"Il faut être à l\'aéroport deux heures avant le départ.\", \"mot_cle\": \"aéroport\"}, {\"texte\": \"J\'ai réservé un hôtel près du centre-ville.\", \"mot_cle\": \"hôtel\"}, {\"texte\": \"Mon passeport expire l\'année prochaine.\", \"mot_cle\": \"passeport\"}, {\"texte\": \"Le vol a été retardé d\'une heure.\", \"mot_cle\": \"retardé\"}, {\"texte\": \"On a visité un musée magnifique hier.\", \"mot_cle\": \"musée\"}, {\"texte\": \"La valise est trop lourde, il faut enlever des affaires.\", \"mot_cle\": \"valise\"}, {\"texte\": \"Nous rentrons à la maison samedi soir.\", \"mot_cle\": \"rentrons\"}, {\"texte\": \"Je ne parle pas très bien la langue du pays.\", \"mot_cle\": \"langue\"}], \"instructions\": \"Votre partenaire annonce le thème puis lit chaque phrase. Répétez-la.\", \"consigne_partenaire\": \"Annoncez le thème. Lisez chaque phrase normalement.\"}'),(34,'Thème : Chez le médecin','difficile','Phrases courantes dans un contexte médical.','',8,'themes','{\"theme\": \"Chez le médecin\", \"phrases\": [{\"texte\": \"J\'ai mal à la gorge depuis trois jours.\", \"mot_cle\": \"gorge\"}, {\"texte\": \"Vous devez prendre ce médicament avant les repas.\", \"mot_cle\": \"médicament\"}, {\"texte\": \"Je vous prescris des antibiotiques pour dix jours.\", \"mot_cle\": \"antibiotiques\"}, {\"texte\": \"Avez-vous des antécédents médicaux particuliers ?\", \"mot_cle\": \"antécédents\"}, {\"texte\": \"Il faut faire une prise de sang à jeun.\", \"mot_cle\": \"prise de sang\"}, {\"texte\": \"Les résultats de l\'analyse seront disponibles demain.\", \"mot_cle\": \"résultats\"}, {\"texte\": \"Votre tension artérielle est un peu élevée.\", \"mot_cle\": \"tension\"}, {\"texte\": \"Je vous oriente vers un spécialiste.\", \"mot_cle\": \"spécialiste\"}], \"instructions\": \"Votre partenaire annonce le thème puis lit chaque phrase. Répétez-la.\", \"consigne_partenaire\": \"Annoncez le thème. Le vocabulaire médical est plus difficile — donnez le mot clé si besoin.\"}'),(35,'Thème : Au restaurant','difficile','Phrases courantes au restaurant.','',8,'themes','{\"theme\": \"Au restaurant\", \"phrases\": [{\"texte\": \"Avez-vous une réservation au nom de Martin ?\", \"mot_cle\": \"réservation\"}, {\"texte\": \"Je voudrais une table pour deux personnes.\", \"mot_cle\": \"table\"}, {\"texte\": \"Qu\'est-ce que vous recommandez aujourd\'hui ?\", \"mot_cle\": \"recommandez\"}, {\"texte\": \"Le plat du jour est une sole meunière.\", \"mot_cle\": \"plat du jour\"}, {\"texte\": \"L\'addition s\'il vous plaît.\", \"mot_cle\": \"addition\"}, {\"texte\": \"Est-ce que le service est compris ?\", \"mot_cle\": \"service\"}, {\"texte\": \"Je suis allergique aux fruits de mer.\", \"mot_cle\": \"allergique\"}, {\"texte\": \"Pourriez-vous apporter de l\'eau plate s\'il vous plaît ?\", \"mot_cle\": \"eau plate\"}], \"instructions\": \"Votre partenaire annonce le thème puis lit chaque phrase. Répétez-la.\", \"consigne_partenaire\": \"Annoncez le thème. Ce contexte est difficile car il y a souvent du bruit en situation réelle.\"}'),(36,'Court ou très long ?','facile','Votre partenaire dit un mot. Identifiez s\'il est court (1 syllabe) ou très long (4 syllabes et plus).','',3,'court_moyen_long','{\"paires\": [{\"mots\": [\"chat\", \"bibliothèque\"], \"syllabes\": [1, 5]}, {\"mots\": [\"nuit\", \"extraordinaire\"], \"syllabes\": [1, 6]}, {\"mots\": [\"pain\", \"communication\"], \"syllabes\": [1, 5]}, {\"mots\": [\"fleur\", \"magnifiquement\"], \"syllabes\": [1, 5]}, {\"mots\": [\"mer\", \"responsabilité\"], \"syllabes\": [1, 6]}, {\"mots\": [\"bois\", \"réconciliation\"], \"syllabes\": [1, 6]}, {\"mots\": [\"thé\", \"vraisemblablement\"], \"syllabes\": [1, 6]}, {\"mots\": [\"sol\", \"individualité\"], \"syllabes\": [1, 6]}, {\"mots\": [\"mur\", \"incompréhensible\"], \"syllabes\": [1, 6]}, {\"mots\": [\"rue\", \"internationalisation\"], \"syllabes\": [1, 8]}], \"instructions\": \"Votre partenaire dit l\'un des deux mots. Montrez ou dites lequel il a prononcé.\", \"consigne_partenaire\": \"Choisissez l\'un des deux mots de chaque paire et prononcez-le clairement. Attendez la réponse.\"}'),(37,'Écart de syllabes croissant','moyen','Identifiez le mot prononcé parmi deux options. L\'écart de syllabes diminue progressivement.','',3,'court_moyen_long','{\"niveaux\": {\"A_ecart_4\": [{\"mots\": [\"roi\", \"incompréhensible\"]}, {\"mots\": [\"feu\", \"extraordinairement\"]}, {\"mots\": [\"bas\", \"vraisemblablement\"]}], \"B_ecart_3\": [{\"mots\": [\"lait\", \"anniversaire\"]}, {\"mots\": [\"jour\", \"conversation\"]}, {\"mots\": [\"paix\", \"responsable\"]}], \"C_ecart_2\": [{\"mots\": [\"chat\", \"maison\"]}, {\"mots\": [\"peur\", \"avion\"]}, {\"mots\": [\"tard\", \"cinéma\"]}], \"D_ecart_1\": [{\"mots\": [\"nuit\", \"chemin\"]}, {\"mots\": [\"froid\", \"soleil\"]}, {\"mots\": [\"bras\", \"jardin\"]}]}, \"instructions\": \"Votre partenaire dit l\'un des deux mots. Indiquez lequel.\", \"consigne_partenaire\": \"Lisez les paires dans l\'ordre. Prononcez un seul mot de chaque paire.\"}'),(38,'Quelle phrase a été dite ?','moyen','Votre partenaire lit une phrase parmi quatre. Identifiez laquelle grâce à sa longueur.','',3,'court_moyen_long','{\"groupes\": [[\"Viens.\", \"Tu as faim ?\", \"Il fait beau aujourd\'hui.\", \"Je pense que nous devrions partir très tôt demain matin.\"], [\"Merci.\", \"Il arrive.\", \"Appelle-moi ce soir.\", \"Elle a dit qu\'elle préférait rester à la maison pour regarder la télévision.\"], [\"Pardon ?\", \"C\'est loin.\", \"Je n\'ai pas compris.\", \"Pouvez-vous répéter ce que vous venez de me dire plus lentement s\'il vous plaît ?\"], [\"Attends.\", \"Tu viens ?\", \"Donne-moi ça maintenant.\", \"Le médecin m\'a dit que je devais prendre ce médicament trois fois par jour.\"]], \"instructions\": \"Votre partenaire dit l\'une des quatre phrases. Indiquez laquelle.\", \"consigne_partenaire\": \"Choisissez une phrase parmi les quatre proposées. L\'auditeur voit les quatre phrases écrites.\"}'),(39,'Quelle fin de phrase ?','difficile','Votre partenaire complète la phrase. Identifiez la fin parmi trois options de longueurs différentes.','',3,'court_moyen_long','{\"phrases\": [{\"fins\": [\"du pain.\", \"des céréales avec du lait.\", \"un croissant au beurre accompagné d\'un café chaud.\"], \"debut\": \"Ce matin, j\'ai mangé…\"}, {\"fins\": [\"en mer.\", \"à la montagne.\", \"découvrir les paysages magnifiques de la Bretagne.\"], \"debut\": \"Pour les vacances, nous partons…\"}, {\"fins\": [\"la télé.\", \"un documentaire.\", \"un long film historique sur la Révolution française.\"], \"debut\": \"Hier soir, il a regardé…\"}, {\"fins\": [\"là-bas.\", \"à l\'hôpital.\", \"dans un grand cabinet d\'avocat au centre-ville.\"], \"debut\": \"Elle travaille…\"}, {\"fins\": [\"une voiture.\", \"un appartement.\", \"une belle maison avec jardin et piscine dans le sud de la France.\"], \"debut\": \"Mon voisin a acheté…\"}], \"instructions\": \"Votre partenaire dit la fin de chaque phrase. Les options ont des longueurs très différentes.\", \"consigne_partenaire\": \"Lisez le début de phrase, puis dites l\'une des fins possibles. L\'auditeur doit identifier laquelle.\"}'),(50,'Voyelles : [i] contre [u]','facile','Distinguez les voyelles fermées avant et arrière. Votre partenaire dit l\'un des deux mots.','',5,'distinguer','{\"paires\": [{\"mots\": [\"vie\", \"voue\"]}, {\"mots\": [\"lit\", \"loup\"]}, {\"mots\": [\"ris\", \"roue\"]}, {\"mots\": [\"gris\", \"grou\"]}, {\"mots\": [\"bis\", \"bouse\"]}, {\"mots\": [\"si\", \"sous\"]}, {\"mots\": [\"ni\", \"nous\"]}, {\"mots\": [\"vie\", \"vous\"]}, {\"mots\": [\"tic\", \"toux\"]}, {\"mots\": [\"dit\", \"doux\"]}, {\"mots\": [\"fit\", \"fou\"]}, {\"mots\": [\"mil\", \"mou\"]}], \"principe\": \"Contraste voyelle fermée antérieure [i] contre voyelle fermée postérieure [u]\", \"instructions\": \"Votre partenaire dit l\'un des deux mots. Indiquez lequel vous avez entendu.\", \"consigne_partenaire\": \"Dites un mot de chaque paire. Prononcez très distinctement les voyelles.\"}'),(51,'Voyelles : [u] contre [y]','facile','Distinguez \"ou\" de \"u\". Contraste très fréquent en français entre patients sourds.','',5,'distinguer','{\"paires\": [{\"mots\": [\"tout\", \"tu\"]}, {\"mots\": [\"roue\", \"rue\"]}, {\"mots\": [\"doux\", \"du\"]}, {\"mots\": [\"sous\", \"su\"]}, {\"mots\": [\"bout\", \"bu\"]}, {\"mots\": [\"joue\", \"jus\"]}, {\"mots\": [\"vous\", \"vu\"]}, {\"mots\": [\"cou\", \"cu\"]}, {\"mots\": [\"mou\", \"mu\"]}, {\"mots\": [\"loup\", \"lu\"]}, {\"mots\": [\"pou\", \"pu\"]}, {\"mots\": [\"fou\", \"fut\"]}], \"principe\": \"Contraste [u] postérieur contre [y] antérieur arrondi\", \"instructions\": \"Votre partenaire dit l\'un des deux mots. Lequel avez-vous entendu ?\", \"consigne_partenaire\": \"Prononcez distinctement : \\"ou\\" est arrondi et reculé, \\"u\\" est arrondi et avancé.\"}'),(52,'Voyelles orales contre nasales','moyen','Distinguez une voyelle orale de sa contrepartie nasale. Contraste fondamental du français.','',5,'distinguer','{\"paires\": [{\"mots\": [\"beau\", \"bon\"]}, {\"mots\": [\"seau\", \"son\"]}, {\"mots\": [\"fée\", \"fin\"]}, {\"mots\": [\"paix\", \"pain\"]}, {\"mots\": [\"dos\", \"don\"]}, {\"mots\": [\"mot\", \"mon\"]}, {\"mots\": [\"veau\", \"vin\"]}, {\"mots\": [\"pot\", \"pont\"]}, {\"mots\": [\"eau\", \"an\"]}, {\"mots\": [\"faux\", \"fan\"]}, {\"mots\": [\"bague\", \"banque\"]}, {\"mots\": [\"page\", \"panse\"]}, {\"mots\": [\"sage\", \"sangle\"]}, {\"mots\": [\"cage\", \"cante\"]}, {\"mots\": [\"tape\", \"tante\"]}], \"principe\": \"Contraste voyelle orale vs voyelle nasale correspondante\", \"instructions\": \"Votre partenaire dit l\'un des deux mots. Indiquez lequel.\", \"consigne_partenaire\": \"Contrastez voyelle nasale (résonnance dans le nez) et voyelle orale.\"}'),(53,'Consonnes voisées contre non-voisées','moyen','Distinguez [p/b], [t/d], [k/g], [f/v], [s/z], [ch/j]. Seul le voisement change.','',5,'distinguer','{\"paires\": [{\"mots\": [\"pain\", \"bain\"]}, {\"mots\": [\"pas\", \"bas\"]}, {\"mots\": [\"pont\", \"bond\"]}, {\"mots\": [\"toit\", \"doigt\"]}, {\"mots\": [\"tour\", \"dour\"]}, {\"mots\": [\"tant\", \"dans\"]}, {\"mots\": [\"cou\", \"goût\"]}, {\"mots\": [\"car\", \"gare\"]}, {\"mots\": [\"quai\", \"gai\"]}, {\"mots\": [\"fan\", \"van\"]}, {\"mots\": [\"fond\", \"vont\"]}, {\"mots\": [\"feu\", \"vœu\"]}, {\"mots\": [\"sou\", \"zou\"]}, {\"mots\": [\"seau\", \"zoo\"]}, {\"mots\": [\"chaud\", \"jeu\"]}], \"principe\": \"Contraste voisé vs non-voisé — même lieu et même mode d\'articulation\", \"instructions\": \"Votre partenaire dit l\'un des deux mots. Lequel avez-vous entendu ?\", \"consigne_partenaire\": \"Seul le voisement de la consonne initiale change. Prononcez très nettement.\"}'),(54,'Lieu d\'articulation : bilabiale, dentale, vélaire','difficile','Distinguez [p/t/k] et [b/d/g]. Seul le lieu d\'articulation change.','',5,'distinguer','{\"principe\": \"Contraste lieu d\'articulation : bilabiale [p/b] — dentale [t/d] — vélaire [k/g]\", \"triplets\": [{\"mots\": [\"pain\", \"teint\", \"kain\"]}, {\"mots\": [\"bas\", \"das\", \"gaz\"]}, {\"mots\": [\"pont\", \"ton\", \"con\"]}, {\"mots\": [\"père\", \"terre\", \"guerre\"]}, {\"mots\": [\"bain\", \"daim\", \"gain\"]}, {\"mots\": [\"port\", \"tort\", \"corps\"]}, {\"mots\": [\"part\", \"tare\", \"car\"]}, {\"mots\": [\"peur\", \"teur\", \"cœur\"]}, {\"mots\": [\"beau\", \"dos\", \"goo\"]}, {\"mots\": [\"pic\", \"tic\", \"quiche\"]}], \"instructions\": \"Votre partenaire dit l\'un des trois mots. Indiquez lequel.\", \"consigne_partenaire\": \"Les trois mots ne diffèrent que par le lieu d\'articulation de la consonne.\"}'),(55,'Mode d\'articulation : [t] contre [s]','difficile','Distinguez l\'occlusive dentale [t] de la fricative [s]. Seul le mode d\'articulation change.','',5,'distinguer','{\"paires\": [{\"mots\": [\"tac\", \"sac\"]}, {\"mots\": [\"toi\", \"soie\"]}, {\"mots\": [\"ton\", \"son\"]}, {\"mots\": [\"tout\", \"soûl\"]}, {\"mots\": [\"tu\", \"su\"]}, {\"mots\": [\"thé\", \"ces\"]}, {\"mots\": [\"tir\", \"sir\"]}, {\"mots\": [\"telle\", \"sel\"]}, {\"mots\": [\"temps\", \"sans\"]}, {\"mots\": [\"tôt\", \"sot\"]}, {\"mots\": [\"tante\", \"sente\"]}, {\"mots\": [\"taille\", \"saille\"]}], \"principe\": \"Contraste mode d\'articulation : occlusive [t] vs fricative [s], même voisement et même lieu\", \"instructions\": \"Votre partenaire dit l\'un des deux mots. Indiquez lequel.\", \"consigne_partenaire\": \"[t] est une occlusive (l\'air est bloqué puis relâché). [s] est une fricative (flux d\'air continu).\"}'),(56,'Phrases riches en sons aigus ou graves','moyen','Identifiez la phrase prononcée. Les phrases A contiennent des sons aigus (fricatives), les B des sons graves (nasales, voyelles ouvertes).','',5,'distinguer','{\"paires\": [{\"A_aigu\": \"Ses chaussettes sont sèches.\", \"B_grave\": \"Mon bon ami vient demain.\"}, {\"A_aigu\": \"Six saucisses sèchent sur le sol.\", \"B_grave\": \"La lune brille dans le ciel noir.\"}, {\"A_aigu\": \"Zoé choisit ses vêtements seule.\", \"B_grave\": \"Mon grand frère aime la montagne.\"}, {\"A_aigu\": \"Ce sac est si léger.\", \"B_grave\": \"Viens donc voir ma grand-mère.\"}, {\"A_aigu\": \"La sœur de Cécile s\'est perdue.\", \"B_grave\": \"Mon voisin promène son grand chien.\"}, {\"A_aigu\": \"C\'est si facile de réussir.\", \"B_grave\": \"Un bon bain chaud, ça fait du bien.\"}, {\"A_aigu\": \"Ces chaussures sont usées.\", \"B_grave\": \"Maman range les valises là-haut.\"}, {\"A_aigu\": \"Elle choisit souvent ce chemin-ci.\", \"B_grave\": \"Mon grand ami mange très bien.\"}], \"principe\": \"Contraste fréquentiel : phrases riches en fricatives et sibilantes (hautes fréquences) vs phrases riches en nasales et voyelles ouvertes (basses fréquences)\", \"instructions\": \"Votre partenaire dit une phrase A ou B. Indiquez laquelle.\", \"consigne_partenaire\": \"Dites l\'une des deux phrases sans montrer votre visage si possible. L\'auditeur voit les deux options écrites.\"}'),(57,'Quel mot est accentué ?','moyen','En français, on peut insister sur un mot pour changer le sens. Identifiez le mot sur lequel votre partenaire a mis l\'emphase.','',3,'percevoir','{\"phrases\": [{\"phrase\": \"Tu as pris mon stylo.\", \"mots_cles\": [\"Tu\", \"pris\", \"mon\", \"stylo\"]}, {\"phrase\": \"Elle est déjà partie.\", \"mots_cles\": [\"Elle\", \"déjà\", \"partie\"]}, {\"phrase\": \"Je veux du café chaud.\", \"mots_cles\": [\"Je\", \"veux\", \"café\", \"chaud\"]}, {\"phrase\": \"Il n\'a pas répondu.\", \"mots_cles\": [\"Il\", \"pas\", \"répondu\"]}, {\"phrase\": \"Nous partons ce soir.\", \"mots_cles\": [\"Nous\", \"partons\", \"soir\"]}, {\"phrase\": \"C\'est vraiment trop tard.\", \"mots_cles\": [\"vraiment\", \"trop\", \"tard\"]}, {\"phrase\": \"Donne-moi ça maintenant.\", \"mots_cles\": [\"Donne\", \"ça\", \"maintenant\"]}, {\"phrase\": \"Tu as dit que tu venais.\", \"mots_cles\": [\"Tu\", \"dit\", \"tu\", \"venais\"]}], \"instructions\": \"Votre partenaire lit une phrase en insistant sur un mot différent à chaque fois. Indiquez quel mot vous semblez avoir entendu avec plus d\'intensité ou de durée.\", \"consigne_partenaire\": \"Lisez la phrase en exagérant l\'accent d\'intensité sur le mot indiqué par le numéro choisi.\"}'),(58,'Formules de tous les jours','facile','Votre partenaire dit une formule très courante. Identifiez laquelle parmi les options.','',4,'reconnaitre','{\"groupes\": [[\"Bonjour !\", \"Bonsoir.\", \"Bonne nuit.\", \"Salut !\"], [\"Comment ça va ?\", \"Ça va bien.\", \"Pas trop mal.\", \"Ça va très bien, merci.\"], [\"S\'il vous plaît.\", \"Merci beaucoup.\", \"Je vous en prie.\", \"De rien.\"], [\"Pardon ?\", \"Excusez-moi.\", \"Je n\'ai pas compris.\", \"Pouvez-vous répéter ?\"], [\"Oui, bien sûr.\", \"Non, merci.\", \"Peut-être.\", \"Je ne sais pas.\"], [\"C\'est combien ?\", \"C\'est cher.\", \"Avez-vous la monnaie ?\", \"Je paie par carte.\"], [\"À quelle heure ?\", \"Quand est-ce ?\", \"C\'est pour quand ?\", \"Quel jour sommes-nous ?\"], [\"Où sont les toilettes ?\", \"C\'est par là.\", \"Tournez à gauche.\", \"C\'est tout droit.\"]], \"instructions\": \"Votre partenaire dit l\'une des formules. Indiquez laquelle vous avez reconnue.\", \"consigne_partenaire\": \"Choisissez une formule parmi le groupe et dites-la clairement. Maximum 3 tentatives avant d\'aider.\"}'),(59,'Sujet : La télévision','moyen','Votre partenaire dit des phrases sur le thème de la télévision. Répétez ou identifiez chaque phrase.','',8,'themes','{\"theme\": \"Télévision\", \"phrases\": [{\"phrase\": \"Qu\'est-ce que tu regardes ?\", \"mot_cle\": \"regardes\"}, {\"phrase\": \"Allume la télévision.\", \"mot_cle\": \"télévision\"}, {\"phrase\": \"Je déteste les publicités.\", \"mot_cle\": \"publicités\"}, {\"phrase\": \"Il y a un bon film ce soir.\", \"mot_cle\": \"film\"}, {\"phrase\": \"Quel est l\'acteur principal ?\", \"mot_cle\": \"acteur\"}, {\"phrase\": \"Passe-moi la télécommande.\", \"mot_cle\": \"télécommande\"}, {\"phrase\": \"Le journal télévisé commence à vingt heures.\", \"mot_cle\": \"journal\"}, {\"phrase\": \"Change de chaîne, s\'il te plaît.\", \"mot_cle\": \"chaîne\"}, {\"phrase\": \"Cette émission est vraiment intéressante.\", \"mot_cle\": \"émission\"}, {\"phrase\": \"Baisses le volume un peu.\", \"mot_cle\": \"volume\"}], \"instructions\": \"Votre partenaire annonce le thème \\"Télévision\\", puis dit des phrases sur ce sujet. Répétez chaque phrase.\", \"consigne_partenaire\": \"Annoncez le thème. Dites chaque phrase une fois. Si l\'auditeur ne comprend pas en 3 essais, donnez le mot souligné comme indice.\"}'),(60,'Sujet : La nourriture','moyen','Votre partenaire dit des phrases sur le thème de la nourriture. Répétez ou identifiez chaque phrase.','',8,'themes','{\"theme\": \"Nourriture\", \"phrases\": [{\"phrase\": \"J\'ai très faim.\", \"mot_cle\": \"faim\"}, {\"phrase\": \"Qu\'est-ce qu\'on mange ce soir ?\", \"mot_cle\": \"mange\"}, {\"phrase\": \"Le dîner est prêt.\", \"mot_cle\": \"dîner\"}, {\"phrase\": \"Tu veux encore de la soupe ?\", \"mot_cle\": \"soupe\"}, {\"phrase\": \"Ce pain est très frais.\", \"mot_cle\": \"pain\"}, {\"phrase\": \"Je voudrais un café, s\'il vous plaît.\", \"mot_cle\": \"café\"}, {\"phrase\": \"Cette tarte est délicieuse.\", \"mot_cle\": \"tarte\"}, {\"phrase\": \"Passe-moi le sel et le poivre.\", \"mot_cle\": \"sel\"}, {\"phrase\": \"Il n\'y a plus de beurre dans le réfrigérateur.\", \"mot_cle\": \"beurre\"}, {\"phrase\": \"On mange au restaurant ce midi ?\", \"mot_cle\": \"restaurant\"}], \"instructions\": \"Votre partenaire annonce le thème \\"Nourriture\\", puis dit des phrases sur ce sujet. Répétez chaque phrase.\", \"consigne_partenaire\": \"Annoncez le thème. En cas d\'échec après 3 essais, donnez le mot-clé souligné.\"}'),(61,'Sujet : La santé','difficile','Votre partenaire dit des phrases sur le thème de la santé. Répétez chaque phrase sans voir le texte.','',8,'themes','{\"theme\": \"Santé\", \"phrases\": [{\"phrase\": \"J\'ai un rendez-vous chez le médecin.\", \"mot_cle\": \"médecin\"}, {\"phrase\": \"Je me sens vraiment fatigué.\", \"mot_cle\": \"fatigué\"}, {\"phrase\": \"Il faut prendre ce médicament trois fois par jour.\", \"mot_cle\": \"médicament\"}, {\"phrase\": \"Est-ce que tu as de l\'aspirine ?\", \"mot_cle\": \"aspirine\"}, {\"phrase\": \"Mon dos me fait vraiment mal.\", \"mot_cle\": \"dos\"}, {\"phrase\": \"Je dois aller aux urgences.\", \"mot_cle\": \"urgences\"}, {\"phrase\": \"Le docteur m\'a prescrit un traitement.\", \"mot_cle\": \"traitement\"}, {\"phrase\": \"Je tosse depuis plusieurs jours.\", \"mot_cle\": \"tosse\"}, {\"phrase\": \"Il faut se reposer.\", \"mot_cle\": \"reposer\"}, {\"phrase\": \"Avez-vous de la fièvre ?\", \"mot_cle\": \"fièvre\"}], \"instructions\": \"Votre partenaire annonce le thème \\"Santé\\" et dit des phrases. Répétez sans regarder.\", \"consigne_partenaire\": \"L\'auditeur ne voit PAS les phrases écrites. Dites chaque phrase naturellement. 3 essais max puis mot-clé.\"}'),(62,'Questions sur votre quotidien','moyen','Votre partenaire vous pose des questions sur votre vie quotidienne dans différents contextes.','',6,'comprendre','{\"groupes\": [{\"contexte\": \"Questions sur vous\", \"questions\": [\"Comment vous appelez-vous ?\", \"Quel est votre âge ?\", \"Êtes-vous marié(e) ou célibataire ?\", \"Combien avez-vous d\'enfants ?\", \"Quel est votre métier ?\"]}, {\"contexte\": \"Questions sur votre maison\", \"questions\": [\"Où habitez-vous ?\", \"Vous vivez dans une maison ou un appartement ?\", \"Avez-vous un grand jardin ?\", \"C\'est loin d\'ici ?\", \"Depuis combien de temps vivez-vous là ?\"]}, {\"contexte\": \"Questions sur vos préférences\", \"questions\": [\"Vous aimez regarder la télévision ?\", \"Quelle est votre couleur préférée ?\", \"Vous préférez le café ou le thé ?\", \"Qu\'est-ce que vous faites le week-end ?\", \"Quel est votre plat préféré ?\"]}], \"instructions\": \"Votre partenaire vous pose des questions. Répétez la question entendue, puis répondez.\", \"consigne_partenaire\": \"Annoncez chaque sous-thème, puis posez les questions. L\'auditeur répète puis répond.\"}'),(63,'Complétez la phrase (choix visible)','moyen','Votre partenaire lit une phrase avec un mot-clé. Identifiez le bon mot parmi les options visibles.','',6,'comprendre','{\"phrases\": [{\"debut\": \"Si tu as froid, mets ton ______.\", \"options\": [\"manteau\", \"pull\", \"gilet\"]}, {\"debut\": \"J\'ai acheté du lait au ______.\", \"options\": [\"supermarché\", \"marché\", \"magasin\"]}, {\"debut\": \"Est-ce que tu as lu le ______ ce matin ?\", \"options\": [\"journal\", \"livre\", \"magazine\"]}, {\"debut\": \"Je suis allé au cinéma ______.\", \"options\": [\"hier soir\", \"la semaine dernière\", \"samedi\"]}, {\"debut\": \"Elle a mis les fleurs dans le ______.\", \"options\": [\"vase\", \"verre\", \"jardin\"]}, {\"debut\": \"Ouvre la ______ pour faire entrer l\'air.\", \"options\": [\"fenêtre\", \"porte\", \"voiture\"]}, {\"debut\": \"Le boulanger a vendu le ______ au client.\", \"options\": [\"pain\", \"gâteau\", \"croissant\"]}, {\"debut\": \"Il a collé un ______ sur l\'enveloppe.\", \"options\": [\"timbre\", \"autocollant\", \"étiquette\"]}, {\"debut\": \"Nous partons en vacances au ______.\", \"options\": [\"bord de la mer\", \"ski\", \"camping\"]}, {\"debut\": \"Elle travaille à l\'______.\", \"options\": [\"hôpital\", \"école\", \"usine\"]}], \"instructions\": \"Votre partenaire lit la phrase complète. Indiquez quel mot de la liste a été prononcé.\", \"consigne_partenaire\": \"Choisissez une des options pour chaque phrase et lisez la phrase complète. L\'auditeur voit les options mais pas la phrase entière.\"}'),(64,'Complétez la phrase (sans indices)','difficile','Votre partenaire lit une phrase complète. Répétez le mot manquant sans voir les options.','',6,'comprendre','{\"phrases\": [{\"complet\": \"Si tu as froid, mets ton manteau.\", \"reponse\": \"manteau\", \"visible\": \"Si tu as froid, mets ton ______.\"}, {\"complet\": \"J\'ai acheté du lait au supermarché.\", \"reponse\": \"supermarché\", \"visible\": \"J\'ai acheté du lait au ______.\"}, {\"complet\": \"Est-ce que tu as lu le journal ce matin ?\", \"reponse\": \"journal\", \"visible\": \"Est-ce que tu as lu le ______ ce matin ?\"}, {\"complet\": \"Elle a mis les fleurs dans le vase.\", \"reponse\": \"vase\", \"visible\": \"Elle a mis les fleurs dans le ______.\"}, {\"complet\": \"Ouvre la fenêtre pour faire entrer l\'air.\", \"reponse\": \"fenêtre\", \"visible\": \"Ouvre la ______ pour faire entrer l\'air.\"}, {\"complet\": \"Il a collé un timbre sur l\'enveloppe.\", \"reponse\": \"timbre\", \"visible\": \"Il a collé un ______ sur l\'enveloppe.\"}, {\"complet\": \"Nous partons en vacances au bord de la mer.\", \"reponse\": \"bord de la mer\", \"visible\": \"Nous partons en vacances au ______.\"}, {\"complet\": \"Le médecin m\'a prescrit un médicament.\", \"reponse\": \"médicament\", \"visible\": \"Le médecin m\'a prescrit un ______.\"}, {\"complet\": \"Le train a une heure de retard.\", \"reponse\": \"retard\", \"visible\": \"Le train a une heure de ______.\"}, {\"complet\": \"Les enfants jouent dans le jardin.\", \"reponse\": \"jardin\", \"visible\": \"Les enfants jouent dans le ______.\"}], \"instructions\": \"Vous voyez la phrase avec un blanc. Votre partenaire dit la phrase complète. Répétez le mot manquant.\", \"consigne_partenaire\": \"L\'auditeur voit seulement la phrase avec le blanc. Lisez la phrase entière naturellement.\"}'),(65,'Histoire : Le petit déjeuner','moyen','Votre partenaire vous lit un court texte sur le petit déjeuner. Répondez ensuite aux questions.','',6,'comprendre','{\"texte\": \"Le petit déjeuner est probablement le repas le plus important de la journée. Il nous donne l\'énergie nécessaire pour passer la matinée. En France, beaucoup de gens mangent du pain avec du beurre et de la confiture. D\'autres préfèrent des céréales avec du lait. Certains aiment les croissants ou les pains au chocolat du boulanger. La plupart des adultes boivent du café ou du thé. Les enfants préfèrent souvent le jus d\'orange. Un bon petit déjeuner devrait contenir des protéines, des glucides et des vitamines.\", \"questions\": [{\"q\": \"De quoi parlais-je ?\", \"type\": \"sujet\"}, {\"q\": \"Pourquoi le petit déjeuner est-il important ?\", \"type\": \"rappel\"}, {\"q\": \"Que mangent beaucoup de Français ?\", \"type\": \"rappel\"}, {\"q\": \"Que boivent les enfants en général ?\", \"type\": \"rappel\"}, {\"q\": \"Et vous, que prenez-vous au petit déjeuner ?\", \"type\": \"personnel\"}], \"instructions\": \"Votre partenaire vous lit le texte à voix haute sans vous montrer le livre. Répondez ensuite aux questions.\", \"consigne_partenaire\": \"Lisez le texte lentement et clairement. L\'auditeur ne voit pas le texte. Posez ensuite les questions une par une.\"}'),(66,'Histoire : Le chat et l\'oiseau','difficile','Votre partenaire vous lit une histoire narrative. Répondez ensuite aux questions précises.','',6,'comprendre','{\"texte\": \"Un après-midi d\'été, un gros chat roux était couché sur le rebord d\'une fenêtre. Il regardait le jardin d\'un œil à moitié fermé. Soudain, il aperçut un petit oiseau jaune posé sur une branche basse du pommier. L\'oiseau chantait sans se méfier. Le chat se redressa lentement, descendit du rebord avec précaution, et se faufila entre les buissons. Il s\'approcha tout doucement, centimètre par centimètre. Mais au moment où il allait bondir, l\'oiseau l\'aperçut et s\'envola. Le chat sauta dans le vide et tomba dans le bassin du jardin. Il rentra à la maison, furieux et tout mouillé, et ne quitta plus son coussin de toute la journée.\", \"questions\": [{\"q\": \"De quelle couleur était le chat ?\", \"reponse\": \"roux\"}, {\"q\": \"Où était-il couché ?\", \"reponse\": \"sur le rebord d\'une fenêtre\"}, {\"q\": \"De quelle couleur était l\'oiseau ?\", \"reponse\": \"jaune\"}, {\"q\": \"Sur quoi l\'oiseau était-il posé ?\", \"reponse\": \"une branche basse du pommier\"}, {\"q\": \"Est-ce que le chat a attrapé l\'oiseau ?\", \"reponse\": \"non\"}, {\"q\": \"Où est-il tombé ?\", \"reponse\": \"dans le bassin du jardin\"}, {\"q\": \"Qu\'a-t-il fait en rentrant ?\", \"reponse\": \"il n\'a plus quitté son coussin\"}], \"instructions\": \"Votre partenaire vous lit l\'histoire. Essayez de retenir les détails. Répondez ensuite sans aide.\", \"consigne_partenaire\": \"Lisez l\'histoire d\'une traite. Posez les questions sans relire le texte.\"}'),(67,'Histoire : Le Mont-Saint-Michel','difficile','Votre partenaire vous lit un texte informatif sur le Mont-Saint-Michel. Répondez aux questions.','',6,'comprendre','{\"texte\": \"Le Mont-Saint-Michel est l\'un des sites les plus visités de France. Il se trouve en Normandie, à la frontière de la Bretagne, dans une baie célèbre pour ses marées exceptionnelles. L\'abbaye bénédictine qui le surmonte a été fondée au VIIIe siècle. Pendant des siècles, des milliers de pèlerins ont traversé la baie à pied pour visiter le sanctuaire. Ce chemin était dangereux car la mer monte très vite dans la baie — parfois à la vitesse d\'un cheval au galop. Aujourd\'hui, plus de trois millions de visiteurs viennent chaque année admirer ce rocher granitique et son abbaye gothique. Depuis 2014, une passerelle piétonne remplace l\'ancienne route submersible, et le mont est redevenu une île à marée haute.\", \"questions\": [{\"q\": \"Où se trouve le Mont-Saint-Michel ?\", \"reponse\": \"en Normandie, à la frontière de la Bretagne\"}, {\"q\": \"Quand l\'abbaye a-t-elle été fondée ?\", \"reponse\": \"au VIIIe siècle\"}, {\"q\": \"Pourquoi la traversée à pied était-elle dangereuse ?\", \"reponse\": \"la mer monte très vite\"}, {\"q\": \"Combien de visiteurs viennent chaque année ?\", \"reponse\": \"plus de trois millions\"}, {\"q\": \"Qu\'est-ce qui a changé depuis 2014 ?\", \"reponse\": \"une passerelle piétonne a été construite\"}, {\"q\": \"Voudriez-vous y aller ? Pourquoi ?\", \"type\": \"personnel\"}], \"instructions\": \"Votre partenaire vous lit le texte sans vous montrer le livre. Répondez ensuite aux questions.\", \"consigne_partenaire\": \"Lisez le texte lentement. Posez les questions sans relire. Si nécessaire, relisez UNE seule phrase.\"}'),(68,'Phrases libres courtes (5-7 mots)','moyen','Votre partenaire dit des phrases courtes sans aucun indice. Répétez chaque phrase entendue.','',4,'reconnaitre','{\"phrases\": [\"J\'ai mis mon argent à la banque.\", \"Elle est malade, appelez le médecin.\", \"Il fait froid ce matin.\", \"Mets tes chaussures avant de sortir.\", \"Le rouge et le bleu font du violet.\", \"Les oiseaux volent haut dans le ciel.\", \"Ferme la porte derrière toi.\", \"Je rentre à la maison ce soir.\", \"Peux-tu m\'aider s\'il te plaît ?\", \"Il est déjà midi.\"], \"instructions\": \"Votre partenaire dit une phrase. Répétez-la sans aide. 3 essais maximum, puis votre partenaire peut donner un indice.\", \"consigne_partenaire\": \"Dites chaque phrase sans que l\'auditeur voie le texte. Si 3 tentatives échouent : donnez d\'abord le sujet général, puis le premier mot.\"}'),(69,'Phrases libres longues (8-12 mots)','difficile','Votre partenaire dit des phrases plus longues sans aucun indice. Répétez chaque phrase.','',4,'reconnaitre','{\"phrases\": [\"La pluie a duré toute la journée sans s\'arrêter.\", \"Les adolescents adorent passer du temps sur leur téléphone.\", \"Il a garé la voiture devant le supermarché du quartier.\", \"Je n\'ai pas assez d\'argent pour acheter ce manteau.\", \"La cuisine a besoin d\'une nouvelle table et de quelques chaises.\", \"Elle a bu un verre de lait chaud avant d\'aller se coucher.\", \"Ils ont emprunté de l\'argent à la banque pour acheter leur maison.\", \"Il faisait encore nuit quand je me suis réveillé ce matin.\", \"Nous avons passé de très belles vacances au bord de la mer.\", \"Son père a posé le livre sur la table de nuit avant d\'éteindre la lumière.\"], \"instructions\": \"Votre partenaire dit une phrase longue. Répétez-la le plus fidèlement possible.\", \"consigne_partenaire\": \"Ces phrases sont longues et sans indice thématique. C\'est la condition la plus difficile. Soyez patient(e).\"}'),(70,'Expressions très familières','facile','Ces expressions sont tellement connues que le contexte aide beaucoup. Répétez chaque expression entendue.','',7,'memoriser','{\"expressions\": [\"C\'est pour vous.\", \"Qui est-ce ?\", \"Gardez ça à l\'esprit.\", \"Allez-y.\", \"Je suis en train de...\", \"Entrez !\", \"En fait...\", \"Après réflexion...\", \"Pas du tout.\", \"Et alors ?\", \"Pas maintenant.\", \"On y va ?\", \"Vous savez ?\", \"C\'est mon stylo ?\", \"Très bien, merci.\", \"D\'accord.\", \"Comment pouvez-vous ?\", \"On part quand ?\", \"Que faire ?\", \"C\'est bon.\", \"Vraiment ?\", \"Bien sûr.\", \"Aucun problème.\", \"On verra.\", \"Ça dépend.\", \"Je vous laisse.\", \"À bientôt !\", \"Bonne journée !\", \"Bonne chance !\", \"Prenez soin de vous.\"], \"instructions\": \"Votre partenaire dit une expression courante. Répétez-la exactement.\", \"consigne_partenaire\": \"Ces formules sont si fréquentes que l\'auditeur les connaît parfaitement. Dites-les naturellement, sans les souligner.\"}'),(71,'Prédire la réponse grâce au contexte','moyen','Votre partenaire lit une question qui vous aide à prédire sa réponse. Répétez la réponse entendue.','',7,'memoriser','{\"paires\": [{\"mot_cle\": \"cauchemars\", \"reponse\": \"Je fais des cauchemars depuis quelques jours.\", \"question\": \"Pourquoi tu ne dors pas ?\"}, {\"mot_cle\": \"pleuvoir\", \"reponse\": \"Parce qu\'il va pleuvoir cet après-midi.\", \"question\": \"Pourquoi tu mets un imperméable ?\"}, {\"mot_cle\": \"train\", \"reponse\": \"On a un train à prendre à six heures du matin.\", \"question\": \"Pourquoi vous partez si tôt ?\"}, {\"mot_cle\": \"lunettes\", \"reponse\": \"Je ne les ai pas trouvées depuis hier soir.\", \"question\": \"Pourquoi tu cherches tes lunettes ?\"}, {\"mot_cle\": \"amis\", \"reponse\": \"On attend des amis à dîner ce soir.\", \"question\": \"Pourquoi tu cuisines autant ?\"}, {\"mot_cle\": \"permis\", \"reponse\": \"Je n\'ai jamais passé le permis de conduire.\", \"question\": \"Pourquoi tu n\'as pas de voiture ?\"}, {\"mot_cle\": \"blague\", \"reponse\": \"Il vient de raconter une blague vraiment drôle.\", \"question\": \"Pourquoi vous riez ?\"}, {\"mot_cle\": \"sensibles\", \"reponse\": \"Mes mains sont très sensibles au soleil.\", \"question\": \"Pourquoi tu portes des gants en été ?\"}, {\"mot_cle\": \"fièvre\", \"reponse\": \"Ma fille a de la fièvre depuis deux jours.\", \"question\": \"Pourquoi tu appelles le médecin ?\"}, {\"mot_cle\": \"articles\", \"reponse\": \"Il y a des articles importants que je veux relire.\", \"question\": \"Pourquoi tu gardes ces vieux journaux ?\"}], \"instructions\": \"Vous lisez la question à votre partenaire. Il vous répond. Répétez sa réponse.\", \"consigne_partenaire\": \"L\'auditeur lit la question, vous répondez avec la réponse de droite. Si l\'auditeur se trompe : répétez, puis accentuez le mot souligné, puis donnez un indice.\"}'),(72,'Racontez-moi un voyage','difficile','Votre partenaire vous pose des questions sur un voyage que vous avez fait. Répondez librement. Exercice de conversation ouverte.','',7,'memoriser','{\"questions\": [\"Où êtes-vous allé(e) ?\", \"Pourquoi avez-vous choisi cet endroit ?\", \"Quand est-ce que vous y êtes allé(e) ?\", \"Vous y êtes allé(e) seul(e) ou avec quelqu\'un ?\", \"Avec qui ?\", \"Comment avez-vous voyagé ?\", \"Combien de temps le voyage a-t-il duré ?\", \"Où avez-vous dormi ?\", \"Qu\'est-ce que vous avez vu en route ?\", \"Quelle était la première chose que vous avez faite en arrivant ?\", \"Qu\'est-ce que vous avez visité ?\", \"Qu\'est-ce que vous avez mangé de particulier ?\", \"Qu\'est-ce qui vous a le plus surpris ?\", \"Avez-vous acheté des souvenirs ?\", \"Combien ça a coûté environ ?\", \"Est-il arrivé quelque chose d\'inattendu ?\", \"Quel est votre plus beau souvenir de ce voyage ?\", \"Y retourneriez-vous ?\", \"Vous me le recommandez ? Pourquoi ?\"], \"instructions\": \"Pensez à un voyage que vous avez fait. Votre partenaire vous pose des questions. Répondez librement. Si vous ne comprenez pas une question, demandez de répéter.\", \"consigne_partenaire\": \"L\'auditeur pense à un voyage. Posez les questions dans l\'ordre. Répétez si nécessaire. Reformulez si l\'auditeur ne comprend pas.\"}'),(73,'Suivez le texte : L\'ours et le chasseur','moyen','Votre partenaire lit un texte pendant que vous suivez chaque mot du doigt. Il s\'arrête à des moments aléatoires. Répétez le dernier mot.','',7,'memoriser','{\"texte\": \"Un vieux chasseur marchait dans la forêt par un matin d\'hiver. La neige recouvrait les sentiers et les arbres craquaient sous le froid. Soudain, il aperçut des empreintes énormes dans la neige fraîche. Son cœur battit plus vite. Ces empreintes appartenaient à un ours, et elles étaient très récentes. Le chasseur suivit la piste pendant plusieurs minutes. Elle le conduisit jusqu\'à une grotte obscure au pied d\'une grande falaise. Il s\'approcha doucement, le souffle retenu. À l\'intérieur, il entendit un souffle profond et régulier. L\'ours dormait encore. Le chasseur sourit, rebroussa chemin sans faire de bruit, et rentra chez lui se réchauffer au coin du feu. Il décida de raconter son aventure à ses petits-enfants le soir même.\", \"instructions\": \"Vous avez le texte sous les yeux. Votre partenaire le lit à voix haute. Suivez chaque mot du doigt. Quand il s\'arrête, répétez le dernier mot qu\'il a dit.\", \"consigne_partenaire\": \"Lisez le texte à voix haute à un rythme naturel. Arrêtez-vous au moins 6 fois à des endroits variés (pas toujours à la fin d\'une phrase). L\'auditeur doit répéter le dernier mot.\", \"points_arret_suggeres\": [\"hiver\", \"froid\", \"neige fraîche\", \"minutes\", \"obscure\", \"régulier\", \"bruit\", \"même\"]}'),(74,'Quel type de réponse attendez-vous ?','difficile','Votre partenaire vous pose différents types de questions. Identifiez d\'abord le type de question, puis répondez.','',7,'memoriser','{\"categories\": {\"oui_non\": [\"Vous savez jouer aux échecs ?\", \"Êtes-vous végétarien(ne) ?\", \"Avez-vous assisté à un mariage récemment ?\", \"Aimez-vous chanter ?\", \"Mangez-vous des olives ?\"], \"affirmations\": [\"Ma mère garde toutes ses vieilles cartes de vœux.\", \"Cette chaise n\'est pas très confortable.\", \"Certains bébés pleurent toute la nuit.\"], \"choix_limite\": [\"Je mets une pomme ou une banane dans votre sac ?\", \"Vous avez réparé la toiture ou elle coule encore ?\", \"C\'est pour aujourd\'hui ou pour demain ?\", \"Vous préférez le train ou la voiture ?\"], \"reponse_ouverte\": [\"Comment pourrait-on améliorer les transports en commun ici ?\", \"Pourquoi est-ce votre ville préférée ?\", \"Que pensez-vous du camping ?\"], \"reponse_precise\": [\"Combien de pièces avez-vous dans votre porte-monnaie ?\", \"À quelle heure est notre rendez-vous demain ?\", \"Quelle chaîne regardez-vous en général le soir ?\"]}, \"instructions\": \"Votre partenaire dit une phrase ou une question. Répétez-la, identifiez son type, puis répondez ou réagissez.\", \"consigne_partenaire\": \"Dites chaque phrase ou question. L\'auditeur répète, dit le type, et répond. Si l\'auditeur se trompe de type, expliquez la différence.\"}'),(75,'Quel mot avez-vous entendu ?','facile','Écoutez trois mots similaires deux fois, puis identifiez le mot prononcé séparément.','',5,'mot_similaire','{\"groupes\": [[\"abus\", \"obus\", \"bus\"], [\"pain\", \"bain\", \"vain\"], [\"mer\", \"ver\", \"fer\"], [\"feu\", \"jeu\", \"peu\"], [\"sac\", \"lac\", \"bac\"], [\"vent\", \"lent\", \"dent\"], [\"rose\", \"pose\", \"dose\"], [\"balle\", \"salle\", \"dalle\"], [\"peur\", \"sœur\", \"heure\"], [\"veau\", \"beau\", \"faux\"], [\"riz\", \"gris\", \"prix\"], [\"tout\", \"doux\", \"toux\"]], \"instructions\": \"Écoutez les trois mots deux fois, puis identifiez celui prononcé seul.\"}');

SET FOREIGN_KEY_CHECKS = 1;

